python3 -c "
import sys,json,requests

data=json.load(sys.stdin)
prompt=data.get('prompt','')

# ===== 1. 自动入库检测 =====
ingest_keywords=['存入向量库','写入向量库','加入向量库']

if any(k in prompt for k in ingest_keywords):
    try:
        r=requests.post('http://127.0.0.1:8765/ingest',json={'text':prompt})
        result=r.json()
        print(json.dumps({
            'hookSpecificOutput':{
                'hookEventName':'UserPromptSubmit',
                'additionalContext':f"\n[RAG] 已写入 {result.get('chunks_added',0)} 个 chunks\n"
            }
        }))
    except Exception as e:
        print(json.dumps({
            'hookSpecificOutput':{
                'hookEventName':'UserPromptSubmit',
                'additionalContext':f"\n[RAG] 写入失败: {str(e)}\n"
            }
        }))

# ===== 2. 自动检索（核心） =====
try:
    r=requests.post('http://127.0.0.1:8765/retrieve',json={'text':prompt})
    chunks=r.json().get('chunks',[])

    if chunks:
        context='\n\n'.join(chunks[:3])
        print(json.dumps({
            'hookSpecificOutput':{
                'hookEventName':'UserPromptSubmit',
                'additionalContext':f"\n[RAG CONTEXT]\n{context}\n"
            }
        }))
except Exception:
    pass
"
